// 增加连接重试逻辑 var conn net.Conn var err error for i := 0; i < 3; i++ { conn, err = net.Dial("tcp", fmt.Sprintf("%s:%d", serverIp, serverPort)) if err == nil { break } fmt.Printf("连接尝试 %d 失败，等待重试...\n", i+1) time.Sleep(2 * time.Second) }
