client.conn = conn return client } ```
4. **添加更详细的错误处理**： ```go func main() { fmt.Println("正在尝试连接服务器...") client := NewClient("127.0.0.1", 8888) if client == nil { fmt.Println("连接服务器失败，请检查：") fmt.Println("1. 服务器是否已启动") fmt.Println("2. 防火墙设置") fmt.Println("3. 端口是否被占用") return } defer client.conn.Close()
fmt.Println(">>>>> 链接服务器成功...") select {} } ```
### 测试步骤： 1. 先启动服务器程序 2. 再运行客户端程序 3. 如果仍然失败，尝试更换端口号（如8889）
### 其他建议： - 可以在服务器端添加日志输出，确认它确实

func NewClient(serverIp string, serverPort int) *Client {
    client := &Client{
        ServerIp:   serverIp,
        ServerPort: serverPort,
    }

    // 增加连接重试逻辑
    var conn net.Conn
    var err error
    for i := 0; i < 3; i++ {
        conn, err = net.Dial("tcp", fmt.Sprintf("%s:%d", serverIp, serverPort))
        if err == nil {
            break
        }
        fmt.Printf("连接尝试 %d 失败，等待重试...\n", i+1)
        time.Sleep(2 * time.Second)
    }

    if err != nil {
        fmt.Println("最终连接失败:", err)
        return nil
    }

    client.conn = conn
    return client
}

func main() {
    fmt.Println("正在尝试连接服务器...")
    client := NewClient("127.0.0.1", 8888)
    if client == nil {
        fmt.Println("连接服务器失败，请检查：")
        fmt.Println("1. 服务器是否已启动")
        fmt.Println("2. 防火墙设置")
        fmt.Println("3. 端口是否被占用")
        return
    }
    defer client.conn.Close()

    fmt.Println(">>>>> 链接服务器成功...")
    select {}
}

